import pytest
from _pytest._io.saferepr import saferepr


def test_broken_getattribute_and_repr():
    """Test that saferepr handles objects with broken __getattribute__ and __repr__."""

    class SomeClass:
        def __getattribute__(self, attr):
            raise RuntimeError("No active exception to reraise")

        def __repr__(self):
            raise RuntimeError("No active exception to reraise")

    obj = SomeClass()
    result = saferepr(obj)

    # Should not raise an exception, and should contain class name
    assert "SomeClass" in result
    assert "raised in repr()" in result
    assert "object at" in result


def test_broken_getattribute_only():
    """Test that saferepr handles objects with broken __getattribute__ but working __repr__."""

    class SomeClass:
        def __getattribute__(self, attr):
            if attr.startswith('_'):
                return object.__getattribute__(self, attr)
            raise AttributeError(f"No attribute {attr}")

    obj = SomeClass()
    result = saferepr(obj)

    # Should work fine since __repr__ still works
    assert "SomeClass" in result


def test_integration_with_pytest():
    """Integration test to ensure pytest doesn't get INTERNALERROR."""

    class SomeClass:
        def __getattribute__(self, attr):
            raise RuntimeError("Broken __getattribute__")

        def __repr__(self):
            raise RuntimeError("Broken __repr__")

    def failing_test():
        SomeClass().attr

    # This should fail the test, but not cause INTERNALERROR
    with pytest.raises(RuntimeError):
        failing_test()


if __name__ == "__main__":
    test_broken_getattribute_and_repr()
    test_broken_getattribute_only()
    test_integration_with_pytest()
    print("All tests passed!")

